支付宝小程序端代码示例
onGetAuthorize(){
    my.getPhoneNumber({
      success: (res) => {
        let encryptedData = res.response;
        console.log('getPhoneNumber-res')
        console.log(encryptedData)
        my.request({
          url: 'https://wxapp.wmj.com.cn/api/Member/getalipayphonenumber',
          method:'POST',
          data:encryptedData,
          success: (resa) => {
            console.log('request-resa')
            console.log(resa)
          },
          fail: (error) => {
            console.log('error')
            console.log(error)
          }
        });
      },
      fail: (res) => {
        console.log(res);
        console.log('getPhoneNumber_fail');
      },
    });
  }
